class CBTAnimationView: NSImageView {
    var imageArray:[AnyObject]?;
    required init?(coder: NSCoder) {
        super.init(coder: coder);
        self.wantsLayer = true;
        self.layerContentsPlacement = NSViewLayerContentsPlacement.ScaleProportionallyToFit;
    }
    func setAnimation(images: [AnyObject])
    {
        self.imageArray = images;
    }
    func startAnimation(fps: Int)
    {
        self.layer?.removeAllAnimations();
        var animation = CAKeyframeAnimation(keyPath: "contents");
        animation.calculationMode = kCAAnimationDiscrete;
        animation.duration = CFTimeInterval(Double(self.imageArray!.count)/Double(fps));
        animation.repeatCount = Float.infinity;
        animation.values = self.imageArray!;
        CATransaction.begin();
        self.layer?.addAnimation(animation, forKey: "contents");
        CATransaction.commit();
    }
    override func drawRect(dirtyRect: NSRect)
    {
        super.drawRect(dirtyRect)
    }
}

class CBTConvertAnimation: CBTConversionOperation
{
    static var imageCoordinator:CBTImageCoordinator?;
    static var JSONCoordinator:CBTJSONCoordinator?;
    var frames:[NSImage];
    var inputSettings:Settings;
    var imageCoordinator = CBTImageCoordinator();
    var JSONCoordinator:CBTJSONCoordinator;
    init(frames:[NSImage], settings:Settings)
    {
        self.inputSettings = settings;
        self.frames = frames;
        self.JSONCoordinator = CBTJSONCoordinator(frames: settings.frameCount);
    }
    override func main()
    {
        NSLog("-[Convert Animation Start]");
        CBTConvertAnimation.imageCoordinator = self.imageCoordinator;
        CBTConvertAnimation.JSONCoordinator = self.JSONCoordinator;
        var hashedFrames = Array<HashedFrame>();
        for var index = 0; index < inputSettings.frameCount; ++index
        {
            hashedFrames.append(HashedFrame(frame: frames[index].unscaledCIImage(), settings: self.inputSettings));
            if (index == 0)
            {
                self.queue.addOperation(CBTConvertFrame(frame: hashedFrames[index], lastFrame: nil, frameNumber: index));
            }
            else
            {
                self.queue.addOperation(CBTConvertFrame(frame: hashedFrames[index], lastFrame: hashedFrames[index-1], frameNumber: index));
            }
        }
        self.queue.waitUntilAllOperationsAreFinished();
        CBTConvertAnimation.imageCoordinator!.writeImage();
        NSLog("Written Cells: %i",CBTConvertAnimation.imageCoordinator!.cells.count);
        NSLog("Written Manifest: %i",CBTConvertAnimation.JSONCoordinator!.data);
        NSLog("-[Convert Animation End]");
    }
}

class CBTConvertCell: CBTConversionOperation
{
    var destinationIndex:Int;
    var frameNumber:Int;
    var cell:HashedCell;
    var lastCellOptional:HashedCell?;
    init(destinationIndex: Int, frameNumber: Int, cell:HashedCell, lastCell:HashedCell?)
    {
        self.destinationIndex = destinationIndex;
        self.frameNumber = frameNumber
        self.cell = cell;
        self.lastCellOptional = lastCell;
    }
    override func main()
    {
        if let lastCell = self.lastCellOptional
        {
            if (cell != lastCell)
            {
                sendWrite();
            }
            else
            {
                NSLog("---[Cell %i in Frame %i Skipped: Static Block]", self.destinationIndex, self.frameNumber);
            }
        }
        else
        {
            sendWrite();
        }
    }
    func sendWrite()
    {
        let sem = dispatch_semaphore_create(0);
        CBTConvertAnimation.imageCoordinator!.addCell(cell, callbackClosure: { (sourceIndex:Int) -> Void in
            CBTConvertAnimation.JSONCoordinator!.addCellData(sourceIndex, destinationIndex: self.destinationIndex, frame: self.frameNumber, callbackClosure: { () -> Void in
                dispatch_semaphore_signal(sem);
            })
        })
        dispatch_semaphore_wait(sem, DISPATCH_TIME_FOREVER);
    }
}

class CBTConvertFrame: CBTConversionOperation
{
    var frame:HashedFrame;
    var lastFrameOptional:HashedFrame?;
    var frameNumber:Int;
    init(frame:HashedFrame, lastFrame:HashedFrame?, frameNumber:Int)
    {
        self.frame = frame;
        self.lastFrameOptional = lastFrame;
        self.frameNumber = frameNumber;
    }
    override func main()
    {
        NSLog("--[Convert Frame %i Start]", self.frameNumber);
        if let lastFrame = lastFrameOptional
        {
            if (frame == lastFrame)
            {
                NSLog("--[Convert Frame %i Skipped: Static Frame]", self.frameNumber);
                return;
            }
            for (index, cell) in enumerate(frame.cells)
            {
                let lastCell = lastFrame.cells[index];
                self.queue.addOperation(CBTConvertCell(destinationIndex: index, frameNumber: self.frameNumber, cell: cell, lastCell: lastCell));
            }
        }
        else
        {
            for (index, cell) in enumerate(frame.cells)
            {
                self.queue.addOperation(CBTConvertCell(destinationIndex: index, frameNumber: self.frameNumber, cell: cell, lastCell: nil));
            }
        }
        self.queue.waitUntilAllOperationsAreFinished();
        NSLog("--[Convert Frame %i End]", self.frameNumber);
    }
}

